#include <stdio.h>
int calculateMaxProfit(int* stockPrices, int stockPricesSize) {
    if (stockPricesSize < 2) return 0;
    int buy[stockPricesSize], sell[stockPricesSize], cooldown[stockPricesSize];
    buy[0] = -stockPrices[0];
    sell[0] = 0;
    cooldown[0] = 0;
    for (int i = 1; i < stockPricesSize; i++) {
        buy[i] = (i > 1) ? (cooldown[i-1] - stockPrices[i]) : (-stockPrices[i]);
        sell[i] = buy[i-1] + stockPrices[i];
        cooldown[i] = (sell[i-1] > cooldown[i-1]) ? sell[i-1] : cooldown[i-1];
        buy[i] = (buy[i] > buy[i-1]) ? buy[i] : buy[i-1];
        sell[i] = (sell[i] > sell[i-1]) ? sell[i] : sell[i-1];
    }
    return (sell[stockPricesSize-1] > cooldown[stockPricesSize-1]) ? sell[stockPricesSize-1] : cooldown[stockPricesSize-1];
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int stockPrices[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &stockPrices[i]);
        }
        printf("%d\n", calculateMaxProfit(stockPrices, N));
    }
    return 0;
}

