const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function calculateMaxProfit(stockPrices) {
    if (stockPrices.length < 2) return 0;
    let buy = [-stockPrices[0]];
    let sell = [0];
    let cooldown = [0];
    for (let i = 1; i < stockPrices.length; i++) {
        buy.push((i > 1) ? (cooldown[i-1] - stockPrices[i]) : (-stockPrices[i]));
        sell.push(buy[i-1] + stockPrices[i]);
        cooldown.push(Math.max(sell[i-1], cooldown[i-1]));
        buy[i] = Math.max(buy[i], buy[i-1]);
        sell[i] = Math.max(sell[i], sell[i-1]);
    }
    return Math.max(sell[sell.length-1], cooldown[cooldown.length-1]);
}
